import{_ as l,p as i,q as e,a1 as a}from"./framework-96b046e1.js";const c={},d=a('<p>在此分享一些我使用的 DC-DC 电源芯片，包括线性稳压芯片和开关型稳压芯片。</p><p>DC-DC 分为升压和降压两种，降压使用的多一点，下面分享出我使用的电源芯片和电路图。</p><h2 id="线性稳压芯片-ldo" tabindex="-1"><a class="header-anchor" href="#线性稳压芯片-ldo" aria-hidden="true">#</a> 线性稳压芯片 LDO</h2><p>我用的线性稳压芯片有：</p><ul><li>AMS1117 <ul><li>封装：SOT-223\\SOT-89</li><li>输入：最大 15V，压差 1.3V@(1A)</li><li>输出：3.3V\\5V、1.8V、其他</li><li>输出电流：1A</li><li>AMS1117 也有可调输出版本的芯片 ADJ</li></ul></li><li>ME6211C33M5G <ul><li>输出：3.3V/500mA、3V/500mA、其他</li><li>输入：最大 6V</li><li>封装：SOT-23-5</li><li>使能引脚：带使能引脚</li></ul></li></ul><h2 id="dcdc-降压芯片" tabindex="-1"><a class="header-anchor" href="#dcdc-降压芯片" aria-hidden="true">#</a> DCDC 降压芯片</h2><ul><li>LM2596 <ul><li>输出：多种输出电压可选，并且有可调版本</li><li>封装：TO-263-5，TO-220-5</li></ul></li><li>XL1509 <ul><li>封装：SOIC-8</li><li>输入：4.5V~40V</li><li>输出：输出电压有多个版本可选，也有可调型号</li><li>输出电流：最大 2A</li></ul></li></ul>',7),r=[d];function t(o,n){return i(),e("div",null,r)}const s=l(c,[["render",t],["__file","dc-dc-power.html.vue"]]);export{s as default};
